import { reportHandoff } from "../analytics.js";
import { requireAuth } from "../config.js";
import { positionalArgs } from "../parseArgs.js";
import { handleStudioError, openStudioTo } from "./openStudioTo.js";
const OPEN_TRACE_PLAN_TIMEOUT_MS = 30 * 60 * 1000;
const ARGS = [{ name: "planId", format: "uuid" }];
export async function runOpenTracePlan(platform, pluginVersion) {
    const args = positionalArgs(ARGS);
    const planId = args[0];
    const { apiKey, serviceUrl } = requireAuth(platform.loginHint);
    const targetPath = `/studio/trace-plan/${encodeURIComponent(planId)}`;
    let decision = "timeout";
    let abort = () => { };
    const timer = setTimeout(() => {
        decision = "timeout";
        abort();
    }, OPEN_TRACE_PLAN_TIMEOUT_MS);
    try {
        const result = await openStudioTo(targetPath, {
            apiKey,
            serviceUrl,
            onEvent: (event) => {
                if (event.type === "tracePlan:confirmed" &&
                    event.data.planId === planId) {
                    clearTimeout(timer);
                    decision = "confirmed";
                    abort();
                    return;
                }
                if (event.type === "tracePlan:cancelled" &&
                    event.data.planId === planId) {
                    clearTimeout(timer);
                    decision = "cancelled";
                    abort();
                    return;
                }
                if (event.type === "studio:session-ended") {
                    clearTimeout(timer);
                    decision = "cancelled";
                    abort();
                }
            },
        });
        abort = result.abort;
        await result.done;
    }
    catch (err) {
        clearTimeout(timer);
        handleStudioError(err);
    }
    if (decision === "timeout") {
        console.error(`Trace plan timed out after ${Math.round(OPEN_TRACE_PLAN_TIMEOUT_MS / 60_000)} minutes [via studio]. The user navigated away without confirming.`);
        process.exit(1);
    }
    if (decision === "confirmed") {
        console.log("Trace plan confirmed [via studio]");
    }
    else {
        console.log("Trace plan cancelled [via studio]");
    }
    // Navigate back to /studio after the decision
    try {
        await openStudioTo("/studio", {
            apiKey,
            serviceUrl,
        });
    }
    catch { }
    await reportHandoff(apiKey, pluginVersion, platform, {
        flow: "tracePlan.confirm",
        wonBy: "studio",
        loopbackAvailable: false,
        ticketAvailable: false,
    });
    process.exit(0);
}
